// ============================================================
// NOTIFICATION BANNER
// ============================================================
function Notification({ notification }) {
  if (!notification) return null;
  const bgMap = { success: C.pass, error: C.fail, warning: C.warning, info: C.info };
  return (
    <div style={{
      position: "fixed", top: 20, left: "50%", transform: "translateX(-50%)",
      background: bgMap[notification.type] || C.accent, color: C.white,
      padding: "12px 24px", borderRadius: 12, zIndex: 1000,
      fontSize: 14, fontWeight: 600, boxShadow: "0 8px 32px rgba(0,0,0,0.5)",
      animation: "slideDown 0.3s ease", maxWidth: "90%", textAlign: "center",
    }}>{notification.msg}</div>
  );
}

// ============================================================
// SECURITY TAG MATCHING (fuzzy 5-digit)
// ============================================================
function matchSecurityTag(input, lotNumber) {
  const cleanInput = input.replace(/\D/g, "");
  const cleanLot = lotNumber.replace(/\D/g, "");
  if (cleanInput.length < 5) return false;
  if (cleanInput === cleanLot) return true;
  if ("0" + cleanInput === cleanLot) return true;
  if (cleanInput === "0" + cleanLot) return true;
  if (cleanInput.length >= 5 && cleanLot.length >= 5) {
    return cleanInput.slice(-5) === cleanLot.slice(-5);
  }
  return false;
}

